Console.WriteLine();

const int warmup = 1000;
const int iterations = 100_000;

// Benchmark helper
void Bench(string name, Action action)
{
    // Warmup
    for (int i = 0; i < warmup; i++) action();

    // Collect multiple samples for statistical robustness
    const int samples = 5;
    double[] elapsed = new double[samples];
    for (int s = 0; s < samples; s++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < iterations; i++) action();
        sw.Stop();
        elapsed[s] = sw.Elapsed.TotalMilliseconds / iterations * 1_000_000; // ns per op
    }
    Array.Sort(elapsed);
    double median = elapsed[samples / 2];
    double min = elapsed[0];
    double max = elapsed[^1];
    Console.WriteLine($"  {name,-38} {median,10:F1} ns/op  (min={min:F1}, max={max:F1})");
}

